{"content": "     1|import { NextResponse } from 'next/server';
     2|import type { NextRequest } from 'next/server';
     3|
     4|export function middleware(request: NextRequest) {
     5|  const ageVerified = request.cookies.get('age-verified')?.value;
     6|  const { pathname } = request.nextUrl;
     7|
     8|  // Don't redirect if already on the age verification page or API routes or static files
     9|  if (
    10|    pathname.startsWith('/verificar-edad') ||
    11|    pathname.startsWith('/api') ||
    12|    pathname.startsWith('/_next') ||
    13|    pathname.startsWith('/admin') ||
    14|    pathname.startsWith('/login') ||
    15|    pathname.includes('.')
    16|  ) {
    17|    return NextResponse.next();
    18|  }
    19|
    20|  if (!ageVerified) {
    21|    const url = request.nextUrl.clone();
    22|    url.pathname = '/verificar-edad';
    23|    url.searchParams.set('redirect', pathname);
    24|    return NextResponse.redirect(url);
    25|  }
    26|
    27|  return NextResponse.next();
    28|}
    29|
    30|export const config = {
    31|  matcher: ['/((?!_next/static|_next/image|favicon.ico|api).*)'],
    32|};
