{"path": "/root/fun4me-store/src/app/(store)/confirmacion/page.tsx", "content": "import { createClient } from '@/lib/supabase/server';
import { redirect } from 'next/navigation';
import Link from 'next/link';
import { Button } from '@/components/ui/button';
import { ShoppingCart } from 'lucide-react';
import ConfirmacionClient from './confirmacion-client';

interface Props {
  searchParams: Promise<{ id?: string }>;
}

export default async function ConfirmacionPage({ searchParams }: Props) {
  const { id } = await searchParams;

  if (!id) {
    return (
      <div className="container mx-auto px-4 py-20 text-center">
        <ShoppingCart className="mx-auto mb-6 h-24 w-24 text-muted-foreground/20" />
        <h1 className="text-2xl font-bold">No hay pedido reciente</h1>
        <p className="mt-2 text-muted-foreground">
          Parece que no tenés un pedido pendiente.
        </p>
        <Link href="/">
          <Button className="mt-6 bg-gradient-to-r from-rose-500 to-purple-600 text-white">
            Ir a la Tienda
          </Button>
        </Link>
      </div>
    );
  }

  const supabase = await createClient();

  const { data: orderData, error } = await supabase
    .from('orders')
    .select('*')
    .eq('id', id)
    .single();

  if (error || !orderData) {
    redirect('/');
  }

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const order = orderData as any;

  // Extraer items del campo JSONB del pedido
  const items = (order.items as Array<{
    product_name: string;
    quantity: number;
    unit_price: number;
    total_price: number;
  }>) || [];

  const orderForClient = {
    id: order.id as string,
    customer_name: (order.customer_name as string) || '',
    customer_phone: (order.customer_phone as string) || '',
    customer_email: (order.customer_email as string | null) || null,
    shipping_address: order.shipping_address as {
      address: string;
      city: string;
      neighborhood: string;
    } | null,
    shipping_zone: (order.shipping_zone as string | null) || null,
    shipping_cost: (order.shipping_cost as number) || 0,
    payment_method: (order.payment_method as string) || 'cod',
    subtotal: (order.subtotal as number) || 0,
    total: (order.total as number) || 0,
    status: (order.status as string) || 'pending',
    notes: (order.notes as string | null) || null,
    created_at: order.created_at as string,
    items,
  };

  return <ConfirmacionClient order={orderForClient} />;
}
"}

{"path": "/root/fun4me-store/src/app/(auth)/login/page.tsx", "content": "'use client';

import { useState, type FormEvent } from 'react';
import { useRouter } from 'next/navigation';
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { createClient } from '@/lib/supabase/client';

export default function LoginPage() {
  const router = useRouter();
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  async function handleSubmit(e: FormEvent<HTMLFormElement>) {
    e.preventDefault();
    setError(null);
    setLoading(true);

    try {
      const supabase = createClient();

      const { error: authError } = await supabase.auth.signInWithPassword({
        email: email.trim(),
        password,
      });

      if (authError) {
        if (authError.message.includes('Invalid login credentials')) {
          setError('Credenciales incorrectas. Verificá tu correo y contraseña.');
        } else if (authError.message.includes('Email not confirmed')) {
          setError('Tu correo aún no fue confirmado. Revisá tu bandeja de entrada.');
        } else {
          setError(authError.message);
        }
        return;
      }

      router.push('/admin');
      router.refresh();
    } catch {
      setError('Error de conexión. Intentá de nuevo más tarde.');
    } finally {
      setLoading(false);
    }
  }

  return (
    <div className="flex min-h-screen items-center justify-center px-4">
      <Card className="w-full max-w-sm">
        <CardHeader className="text-center">
          <CardTitle className="text-2xl">Iniciar Sesión</CardTitle>
          <CardDescription>
            Ingresá tus credenciales para acceder al panel de administración
          </CardDescription>
        </CardHeader>
        <CardContent>
          <form onSubmit={handleSubmit} className="space-y-4">
            {error && (
              <div className="rounded-lg border border-red-200 bg-red-50 p-3 text-sm text-red-700">
                {error}
              </div>
            )}

            <div className="space-y-2">
              <Label htmlFor="email">Correo electrónico</Label>
              <Input
                id="email"
                type="email"
                placeholder="[REDACTED_EMAIL]"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                required
                disabled={loading}
                autoComplete="email"
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="password">Contraseña</Label>
              <Input
                id="password"
                type="password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                required
                disabled={loading}
                autoComplete="current-password"
              />
            </div>
            <Button type="submit" className="w-full" disabled={loading}>
              {loading ? 'Iniciando sesión...' : 'Iniciar Sesión'}
            </Button>
          </form>
        </CardContent>
      </Card>
    </div>
  );
}
"}

{"path": "/root/fun4me-store/src/middleware.ts", "content": "import { NextResponse } from 'next/server';
import type { NextRequest } from 'next/server';
import { createServerClient } from '@supabase/ssr';

export async function middleware(request: NextRequest) {
  const { pathname } = request.nextUrl;

  // Don't redirect if already on the age verification page or API routes or static files
  if (
    pathname.startsWith('/verificar-edad') ||
    pathname.startsWith('/api') ||
    pathname.startsWith('/_next') ||
    pathname.startsWith('/login') ||
    pathname.includes('.')
  ) {
    return NextResponse.next();
  }

  /* ── Admin route protection ──────────────────────────────── */
  if (pathname.startsWith('/admin')) {
    let response = NextResponse.next({
      request: {
        headers: request.headers,
      },
    });

    const supabase = createServerClient(
      process.env.NEXT_PUBLIC_SUPABASE_URL!,
      process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
      {
        cookies: {
          getAll() {
            return request.cookies.getAll();
          },
          setAll(cookiesToSet) {
            cookiesToSet.forEach(({ name, value }) =>
              request.cookies.set(name, value),
            );
            response = NextResponse.next({
              request,
            });
            cookiesToSet.forEach(({ name, value, options }) =>
              response.cookies.set(name, value, options),
            );
          },
        },
      },
    );

    const {
      data: { user },
    } = await supabase.auth.getUser();

    if (!user) {
      const url = request.nextUrl.clone();
      url.pathname = '/login';
      url.searchParams.set('redirect', pathname);
      return NextResponse.redirect(url);
    }

    return response;
  }

  /* ── Age gate for store pages ────────────────────────────── */
  const ageVerified = request.cookies.get('age-verified')?.value;

  if (!ageVerified) {
    const url = request.nextUrl.clone();
    url.pathname = '/verificar-edad';
    url.searchParams.set('redirect', pathname);
    return NextResponse.redirect(url);
  }

  return NextResponse.next();
}

export const config = {
  matcher: ['/((?!_next/static|_next/image|favicon.ico|api).*)'],
};
"}

